// Resolve any image input to a usable URL.
//   short key   →  /assets/imagery/<key>.webp
//   /…path…     →  passthrough
//   http(s)://… →  passthrough
//   nullish     →  Jungle logo fallback
export const IMG_FALLBACK = '/assets/brand/logo-color-primary.png';
export const IMG = (name) => {
  if (!name) return IMG_FALLBACK;
  if (name.startsWith('http') || name.startsWith('/')) return name;
  return `/assets/imagery/${name}.webp`;
};

