export const ROWS = [
  { key:'week',     title:'Happening this week',    filter:(e)=> e.status!=='expired' && (e.when.includes('week')||e.when.includes('today')) },
  { key:'free',     title:'Free things to do',      filter:(e)=> e.status!=='expired' && e.priceType==='free' },
  { key:'festival', title:'Festivals on now',       filter:(e)=> e.status!=='expired' && e.festival },
  { key:'show',     title:'Shows and performances', filter:(e)=> e.status!=='expired' && e.type==='Show' },
  { key:'explore',  title:'Places to explore',      filter:(e)=> e.status!=='expired' && (e.type==='Museum'||e.type==='Attraction') },
  { key:'outdoor',  title:'Outdoor and active',     filter:(e)=> e.status!=='expired' && e.type==='Outdoor' },
];

// Derive compact "S$X" / "$X" amount from freeform pricing text.
function _firstAmount(text){
  if(!text) return null;
  const m = text.match(/S?\$\s?\d+(?:\.\d{1,2})?/i);
  if(!m) return null;
  let s = m[0].replace(/\s+/g,'');
  if(/^\$/.test(s)) s = 'S' + s;
  return s.replace(/^s\$/i,'S$');
}

// Derive structured priceInfo from a record's existing priceType/priceDisplay.
// Returns { type:'free'|'paid'|'mixed', display?, freeFor?, paidDisplay?, note?, fullText? }
export function priceInfoFor(e){
  if(e && e.priceInfo) return e.priceInfo;
  const text = ((e && e.priceDisplay) || '').trim();

  if(e.priceType === 'free'){
    return { type:'free', fullText: text };
  }

  if(e.priceType === 'mixed'){
    const amt = _firstAmount(text);
    // Delimiters between free clause and paid clause are ; or ". " (sentence end),
    // NOT commas — the freeFor phrase often contains commas itself.
    // Pattern A: "Free for X; from $Y for others (note)"
    let m = text.match(/free\b[^;.]*?\bfor\s+(.+?)\s*(?:;|\.\s)\s*(?:from\s+)?([^;]*?)\bfor\s+others?\b\s*(?:\(([^)]+)\))?/i);
    if(m){
      return {
        type:'mixed',
        freeFor: m[1].trim().replace(/\s+/g,' '),
        paidDisplay: amt ? `From ${amt}` : 'Admission applies',
        note: m[3] ? m[3].trim() : null,
        fullText: text
      };
    }
    // Pattern B: "Free for X; general admission applies to others"
    m = text.match(/free\b[^;.]*?\bfor\s+(.+?)\s*(?:;|\.\s)\s*(.+)$/i);
    if(m){
      return {
        type:'mixed',
        freeFor: m[1].trim().replace(/\s+/g,' '),
        paidDisplay: amt ? `From ${amt}` : 'Admission applies',
        note: null,
        fullText: text
      };
    }
    // Pattern C: "Free programme/admission/entry…; <paid bit>"
    m = text.match(/^free\b([^;.]*?)\s*(?:;|\.\s)\s*(.+)$/i);
    if(m){
      const ff = m[1].replace(/^(admission|entry|programme|to)\s*/i,'').trim() || 'entry';
      return {
        type:'mixed',
        freeFor: ff,
        paidDisplay: amt ? `From ${amt}` : 'Some paid',
        note: null,
        fullText: text
      };
    }
    return {
      type:'mixed',
      freeFor: 'some visitors',
      paidDisplay: amt ? `From ${amt}` : 'Some paid',
      note: null,
      fullText: text
    };
  }

  // paid
  const amt = _firstAmount(text);
  return {
    type:'paid',
    display: amt ? `From ${amt}` : (text.length > 28 ? 'Paid entry' : text),
    fullText: text
  };
}

// Compact one-liner used by map pins / spotlight rows.
export function priceText(e){
  const pi = priceInfoFor(e);
  if(pi.type === 'free') return 'Free';
  if(pi.type === 'mixed') return pi.paidDisplay ? `Free · ${pi.paidDisplay}` : 'Mixed';
  return pi.display || 'Paid';
}
